1	package agent
2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"regexp"
8		"strings"
9	)
10	
11	// ACClaim is one structural claim parsed from a bead's acceptance criteria.
12	// It names a concrete artifact (test function, file path, or struct field)
13	// whose state can be checked against the worktree without running tests.
14	//
15	// The already_satisfied gate uses these to refuse closure when the AC names
16	// a structural property the implementation has not actually exercised.
17	type ACClaim struct {
18		Kind  string
19		Value string
20	}
21	
22	const (
23		// ACClaimTestName names a Go test or benchmark function that the AC
24		// expects to pass. The verifier checks whether the no_changes rationale
25		// cites the test by name (the worker must claim to have exercised it).
26		ACClaimTestName = "test_name"
27		// ACClaimFileDeleted names a file path the AC asserts has been removed
28		// or no longer exists. The verifier stats the path under projectRoot.
29		ACClaimFileDeleted = "file_deleted"
30		// ACClaimFieldRemoved names a struct field the AC asserts has been
31		// removed. The verifier scans *.go files under projectRoot for a
32		// declaration of that field.
33		ACClaimFieldRemoved = "field_removed"
34	)
35	
36	var (
37		reACTestName = regexp.MustCompile(`\b(?:Test|Benchmark)[A-Z]\w*\b`)
38	
39		// "<path> deleted|removed|no longer exists"
40		reACFileDeletedTrailing = regexp.MustCompile(`([\w./-]+\.\w+)\s+(?:is\s+)?(?:deleted|removed|no longer exists)`)
41		// "deleted: <path>", "removed: <path>", "no longer contains <path>", "file <path> deleted"
42		reACFileDeletedLeading = regexp.MustCompile(`(?:deleted:?\s+|removed:?\s+|no longer contains?\s+|file\s+)([\w./-]+\.\w+)`)
43	
44		// "field X removed", "field X is gone", "field X has been removed"
45		reACFieldRemovedTrailing = regexp.MustCompile(`(?i)\bfield\s+(\w+)\s+(?:is\s+)?(?:removed|gone|has been removed|deleted)`)
46		// "no field X", "does not have field X", "without field X",
47		// "no longer has field X", "no longer contains field X"
48		reACFieldRemovedLeading = regexp.MustCompile(`(?i)(?:no field|does not have field|without field|no longer (?:has|contains?) field)\s+(\w+)`)
49	)
50	
51	// ParseACClaims extracts structural claims from the acceptance text. Empty
52	// or claim-free acceptance returns nil. Duplicate claims are collapsed.
53	func ParseACClaims(acceptance string) []ACClaim {
54		if acceptance == "" {
55			return nil
56		}
57		seen := map[string]bool{}
58		var claims []ACClaim
59		add := func(kind, value string) {
60			if value == "" {
61				return
62			}
63			key := kind + ":" + value
64			if seen[key] {
65				return
66			}
67			seen[key] = true
68			claims = append(claims, ACClaim{Kind: kind, Value: value})
69		}
70		for _, m := range reACTestName.FindAllString(acceptance, -1) {
71			add(ACClaimTestName, m)
72		}
73		for _, m := range reACFileDeletedTrailing.FindAllStringSubmatch(acceptance, -1) {
74			add(ACClaimFileDeleted, m[1])
75		}
76		for _, m := range reACFileDeletedLeading.FindAllStringSubmatch(acceptance, -1) {
77			add(ACClaimFileDeleted, m[1])
78		}
79		for _, m := range reACFieldRemovedTrailing.FindAllStringSubmatch(acceptance, -1) {
80			add(ACClaimFieldRemoved, m[1])
81		}
82		for _, m := range reACFieldRemovedLeading.FindAllStringSubmatch(acceptance, -1) {
83			add(ACClaimFieldRemoved, m[1])
84		}
85		return claims
86	}
87	
88	// VerifyACClaims checks each claim against the project worktree and the
89	// worker's no_changes rationale. Returns (true, "") if every claim holds.
90	// On the first failure returns (false, reason) describing the unmet claim
91	// so the caller can record why already_satisfied was refused.
92	//
93	// projectRoot may be empty, in which case file/field claims are skipped
94	// (verifier degrades to a rationale-only check). This keeps the function
95	// usable in unit-test contexts where no worktree is available.
96	func VerifyACClaims(claims []ACClaim, projectRoot, rationale string) (bool, string) {
97		for _, c := range claims {
98			switch c.Kind {
99			case ACClaimTestName:
100				if !strings.Contains(rationale, c.Value) {
101					return false, fmt.Sprintf("AC names test %q but no_changes rationale does not cite it", c.Value)
102				}
103			case ACClaimFileDeleted:
104				if projectRoot == "" {
105					continue
106				}
107				p := c.Value
108				if !filepath.IsAbs(p) {
109					p = filepath.Join(projectRoot, p)
110				}
111				if _, err := os.Stat(p); err == nil {
112					return false, fmt.Sprintf("AC claims %q deleted but file still exists", c.Value)
113				}
114			case ACClaimFieldRemoved:
115				if projectRoot == "" {
116					continue
117				}
118				found, err := goFieldDeclared(projectRoot, c.Value)
119				if err == nil && found {
120					return false, fmt.Sprintf("AC claims field %q removed but field still declared", c.Value)
121				}
122			}
123		}
124		return true, ""
125	}
126	
127	// goFieldDeclared reports whether any *.go file under root contains a field
128	// declaration whose name matches `name` (i.e. the identifier followed by a
129	// type token: "Name Type" or "Name *Type" or "Name []Type").
130	func goFieldDeclared(root, name string) (bool, error) {
131		re := regexp.MustCompile(`\b` + regexp.QuoteMeta(name) + `\s+[\*\[\]\w.]+`)
132		found := false
133		err := filepath.Walk(root, func(path string, info os.FileInfo, walkErr error) error {
134			if walkErr != nil || found {
135				return walkErr
136			}
137			if info.IsDir() {
138				base := info.Name()
139				if base == ".git" || base == "node_modules" || base == "vendor" {
140					return filepath.SkipDir
141				}
142				return nil
143			}
144			if !strings.HasSuffix(path, ".go") {
145				return nil
146			}
147			data, err := os.ReadFile(path)
148			if err != nil {
149				return nil
150			}
151			if re.Match(data) {
152				found = true
153			}
154			return nil
155		})
156		return found, err
157	}
